'use server'

import { createClient } from '@/utils/supabase/server'
import { redirect } from 'next/navigation'

function generateShareCode(length = 6) {
  const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789'
  let result = ''
  for (let i = 0; i < length; i++) {
    result += chars.charAt(Math.floor(Math.random() * chars.length))
  }
  return result
}

export type SaveHomeworkInput = {
  id?: string
  title: string
  isPublished: boolean
  questions: {
    id: string
    text: string
    options: string[]
    correctOption: number
  }[]
}

export async function saveHomework(data: SaveHomeworkInput) {
  const supabase = await createClient()

  const {
    data: { user },
  } = await supabase.auth.getUser()

  if (!user) {
    return { error: 'Unauthorized' }
  }

  try {
    let homeworkId = data.id
    let shareCode = null

    // Generate share code if publishing
    if (data.isPublished) {
      shareCode = generateShareCode()
    }

    if (homeworkId) {
       // Update existing homework
       const { error: hwError } = await supabase
        .from('homeworks')
        .update({
           title: data.title,
           is_published: data.isPublished,
           ...(data.isPublished ? { share_code: shareCode, published_at: new Date().toISOString() } : {})
        })
        .eq('id', homeworkId)
        .eq('teacher_id', user.id);

       if (hwError) throw new Error(hwError.message)

       // Delete existing questions to replace them
       await supabase.from('questions').delete().eq('homework_id', homeworkId)

    } else {
       // Create new homework
       const { data: hwData, error: hwError } = await supabase
        .from('homeworks')
        .insert({
           teacher_id: user.id,
           title: data.title,
           is_published: data.isPublished,
           ...(data.isPublished ? { share_code: shareCode, published_at: new Date().toISOString() } : {})
        })
        .select()
        .single();

       if (hwError) throw new Error(hwError.message)
       homeworkId = hwData.id
    }

    // Insert questions
    const questionsToInsert = data.questions.map((q, index) => {
       const optionMap = ['a', 'b', 'c', 'd'] as const
       return {
         homework_id: homeworkId,
         question_text: q.text,
         option_a: q.options[0] || '',
         option_b: q.options[1] || '',
         option_c: q.options[2] || '',
         option_d: q.options[3] || '',
         correct_answer: optionMap[q.correctOption],
         order_index: index,
       }
    })

    if (questionsToInsert.length > 0) {
      const { error: qError } = await supabase.from('questions').insert(questionsToInsert)
      if (qError) throw new Error(qError.message)
    }

    return { success: true, homeworkId, shareCode }

  } catch (error: any) {
    return { error: error.message || 'Failed to save homework' }
  }
}

export async function getHomeworkById(id: string) {
  const supabase = await createClient()

  const { data: { user } } = await supabase.auth.getUser()
  if(!user) return null

  const { data: hw, error } = await supabase
    .from('homeworks')
    .select(`*, questions(*)`)
    .eq('id', id)
    .eq('teacher_id', user.id)
    .single()

  if (error || !hw) return null

  return hw
}

"use client";

import React, { useState, useEffect, Suspense } from 'react';
import Link from 'next/link';
import { useRouter, useSearchParams } from 'next/navigation';
import { Button } from '../../../components/ui/Button';
import { Card, CardContent, CardHeader, CardTitle } from '../../../components/ui/Card';
import { Input } from '../../../components/ui/Input';
import styles from './create.module.css';
import { playSound } from '../../../utils/audio';
import { saveHomework, getHomeworkById } from './actions';

interface Question {
  id: string;
  text: string;
  options: string[];
  correctOption: number;
}

function CreateForm() {
  const searchParams = useSearchParams();
  const editId = searchParams.get('id');
  const router = useRouter();

  const [title, setTitle] = useState('');
  const [questions, setQuestions] = useState<Question[]>([
    { id: '1', text: '', options: ['', '', '', ''], correctOption: 0 }
  ]);
  const [isSaving, setIsSaving] = useState(false);
  const [isLoading, setIsLoading] = useState(!!editId);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    async function fetchHomework() {
      if (!editId) return;
      try {
        const hw = await getHomeworkById(editId);
        if (hw) {
          setTitle(hw.title);
          if (hw.questions && hw.questions.length > 0) {
              const mappedQuestions = (hw.questions as any[]).sort((a,b)=>a.order_index - b.order_index).map(q => {
                  const options = [q.option_a, q.option_b, q.option_c, q.option_d];
                  const qMap: any = { 'a': 0, 'b': 1, 'c': 2, 'd': 3 };
                  return {
                      id: q.id,
                      text: q.question_text,
                      options,
                      correctOption: qMap[q.correct_answer] ?? 0
                  };
              });
              setQuestions(mappedQuestions);
          }
        }
      } catch(err) {
        console.error(err);
      } finally {
        setIsLoading(false);
      }
    }
    fetchHomework();
  }, [editId]);

  const addQuestion = () => {
    playSound('click');
    setQuestions([
      ...questions,
      { id: Date.now().toString(), text: '', options: ['', '', '', ''], correctOption: 0 }
    ]);
  };

  const removeQuestion = (id: string) => {
    playSound('pop');
    if (questions.length > 1) {
      setQuestions(questions.filter(q => q.id !== id));
    }
  };

  const updateQuestionText = (id: string, text: string) => {
    setQuestions(questions.map(q => q.id === id ? { ...q, text } : q));
  };

  const updateOptionText = (qId: string, optIndex: number, text: string) => {
    setQuestions(questions.map(q => {
      if (q.id === qId) {
        const newOptions = [...q.options];
        newOptions[optIndex] = text;
        return { ...q, options: newOptions };
      }
      return q;
    }));
  };

  const setCorrectOption = (qId: string, optIndex: number) => {
    playSound('click');
    setQuestions(questions.map(q => q.id === qId ? { ...q, correctOption: optIndex } : q));
  };

  const handleSave = async (isPublished: boolean) => {
    if (!title.trim()) {
      setError('يرجى إدخال عنوان الواجب');
      return;
    }

    // basic validation
    for (let i = 0; i < questions.length; i++) {
        const q = questions[i];
        if (!q.text.trim()) return setError(`السؤال ${i + 1} يفتقر إلى النص`);
        for (let j = 0; j < q.options.length; j++) {
            if (!q.options[j].trim()) return setError(`السؤال ${i + 1}: الخيار ${j + 1} فارغ`);
        }
    }

    setError(null);
    setIsSaving(true);
    playSound('pop');

    const result = await saveHomework({
        id: editId || undefined,
        title,
        isPublished,
        questions
    });

    setIsSaving(false);
    if (result.error) {
        setError(result.error);
    } else {
        playSound('success');
        router.push('/dashboard');
        router.refresh(); // force refresh dashboard
    }
  };

  if (isLoading) {
      return <div style={{textAlign:'center', padding:'3rem'}}>جاري التحميل...</div>;
  }

  return (
    <div className={styles.container}>
      <div className={styles.header}>
        <div>
          <h1 className={styles.pageTitle}>{editId ? 'تعديل الواجب' : 'إنشاء واجب جديد'}</h1>
        </div>
        <div className={styles.headerActions}>
          <Link href="/dashboard">
            <Button variant="outline" onMouseEnter={() => playSound('pop')}>إلغاء</Button>
          </Link>
          <Button 
            variant="outline" 
            onClick={() => handleSave(false)}
            disabled={isSaving}
          >
            حفظ كمسودة
          </Button>
          <Button 
            variant="primary" 
            className={styles.publishBtn} 
            onMouseEnter={() => playSound('pop')}
            onClick={() => handleSave(true)}
            disabled={isSaving}
          >
            {isSaving ? 'جاري التحميل...' : 'نشر الواجب'}
          </Button>
        </div>
      </div>

      <Card className={styles.mainCard}>
        <CardContent className={styles.formContent}>
          {error && <div style={{color:'red', marginBottom:'1rem'}}>{error}</div>}
          <Input 
            label="عنوان الواجب" 
            placeholder="مثال: مراجعة الفصل الأول" 
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            className={styles.titleInput}
            required
          />

          <div className={styles.questionsList}>
            {questions.map((q, qIndex) => (
              <Card key={q.id} className={styles.questionCard}>
                <CardHeader className={styles.qHeader}>
                  <CardTitle className={styles.qTitle}>السؤال {qIndex + 1}</CardTitle>
                  {questions.length > 1 && (
                    <button 
                      onClick={() => removeQuestion(q.id)}
                      className={styles.removeBtn}
                      type="button"
                    >
                      حذف
                    </button>
                  )}
                </CardHeader>
                <CardContent className={styles.qContent}>
                  <Input 
                    placeholder="مثال: ما وحدة القوة في النظام الدولي؟" 
                    className={styles.qTextInput}
                    value={q.text}
                    onChange={(e) => updateQuestionText(q.id, e.target.value)}
                    required
                  />

                  <div className={styles.optionsList}>
                    {q.options.map((optText, oIndex) => (
                      <div key={oIndex} className={styles.optionRow}>
                        <input 
                          type="radio" 
                          name={`correct-${q.id}`} 
                          className={styles.radioInput}
                          checked={q.correctOption === oIndex}
                          onChange={() => setCorrectOption(q.id, oIndex)}
                          title="اختر كإجابة صحيحة"
                        />
                        <Input 
                          placeholder={`الخيار ${oIndex + 1}`} 
                          className={styles.optionInput} 
                          value={optText}
                          onChange={(e) => updateOptionText(q.id, oIndex, e.target.value)}
                          required
                        />
                      </div>
                    ))}
                  </div>
                </CardContent>
              </Card>
            ))}
          </div>

          <Button 
            variant="outline" 
            className={styles.addQuestionBtn} 
            onClick={addQuestion}
            onMouseEnter={() => playSound('pop')}
            fullWidth
            type="button"
          >
            ＋ إضافة سؤال
          </Button>
        </CardContent>
      </Card>
    </div>
  );
}

export default function CreateHomeworkPage() {
    return (
        <Suspense fallback={<div style={{textAlign:'center', padding:'3rem'}}>جاري التحميل...</div>}>
            <CreateForm />
        </Suspense>
    )
}

import React from 'react';
import Link from 'next/link';
import { Button } from '../../../../components/ui/Button';
import { Card, CardContent } from '../../../../components/ui/Card';
import styles from './results.module.css';
