import { redirect, notFound } from 'next/navigation';
import { CopyLinkButton } from './CopyLinkButton';

export default async function TeacherResultsPage({ params }: { params: Promise<{ id: string }> }) {
  const resolvedParams = await params;
  const homeworkId = resolvedParams.id;

  const supabase = await createClient();
  const { data: { user } } = await supabase.auth.getUser();
  if(!user) {
    redirect('/login');
  }

  // Fetch homework
  const { data: hw, error: hwError } = await supabase
    .from('homeworks')
    .select('*')
    .eq('id', homeworkId)
    .eq('teacher_id', user.id)
    .single();

  if (hwError || !hw) {
    notFound();
  }

  // Fetch submissions
  const { data: submissions, error: subError } = await supabase
    .from('submissions')
    .select('*')
    .eq('homework_id', homeworkId)
    .order('score', { ascending: false });

  const sortedSubmissions = submissions || [];

  return (
    <div className={styles.container}>
      <div className={styles.topNav}>
        <Link href="/dashboard" className={styles.backLink}>
          &rarr; العودة للواجبات
        </Link>
      </div>

      <div className={styles.header}>
        <div>
          <h1 className={styles.pageTitle}>نتائج الواجب</h1>
          <p className={styles.pageSubtitle}>{hw.title}</p>
        </div>
        <div className={styles.headerActions}>
          {/* Export can be added later if needed */}
          {hw.is_published && hw.share_code && (
             <CopyLinkButton shareCode={hw.share_code} />
          )}
        </div>
      </div>

      <div className={styles.mainContent}>
        <Card className={styles.tableCard}>
          <div className={styles.tableResponsive}>
            {sortedSubmissions.length === 0 ? (
              <div style={{ padding: '3rem', textAlign: 'center', color: 'var(--muted-foreground)' }}>
                 لم يقم أي طالب بحل هذا الواجب حتى الآن.
              </div>
            ) : (
              <table className={styles.table}>
                <thead>
                  <tr>
                    <th>اسم الطالب</th>
                    <th>الدرجة</th>
                    <th>وقت التسليم</th>
                  </tr>
                </thead>
                <tbody>
                  {sortedSubmissions.map((student) => (
                    <tr key={student.id}>
                      <td className={styles.studentName}>{student.student_name}</td>
                      <td className={styles.scoreCell}>
                          <span className={(student.score || 0) >= ((student.total_questions || 1) / 2) ? styles.scoreSuccess : styles.scoreDanger}>
                            {student.score} / {student.total_questions}
                          </span>
                      </td>
                      <td>
                          <span style={{color: 'var(--muted-foreground)', fontSize: '0.85rem'}}>
                             {new Date(student.submitted_at).toLocaleString('ar-EG')}
                          </span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}
          </div>
        </Card>

        <div className={styles.sidebar}>
          <Card>
            <div className={styles.rankingHeader}>
              <h3 className={styles.rankingTitle}>ترتيب الطلاب</h3>
              <span className={styles.rankingBadge}>أعلى الدرجات</span>
            </div>
            <CardContent className={styles.rankingContent}>
              <ul className={styles.rankingList}>
                {sortedSubmissions.slice(0, 10).map((student, index) => (
                  <li key={student.id} className={styles.rankingItem}>
                    <div className={styles.rankBadge}>{index + 1}</div>
                    <div className={styles.rankInfo}>
                      <span className={styles.rankName}>{student.student_name}</span>
                      <span className={styles.rankScore}>{student.score} / {student.total_questions}</span>
                    </div>
                  </li>
                ))}
                {sortedSubmissions.length === 0 && (
                  <li style={{textAlign: 'center', color: 'var(--muted-foreground)', padding: '1rem'}}>
                    لا توجد تقييمات
                  </li>
                )}
              </ul>
            </CardContent>
          </Card>
        </div>
      </div>
    </div>
  );
}

