'use server'

import { createClient } from '@/utils/supabase/server'

export async function getHomeworkByShareCode(shareCode: string) {
  const supabase = await createClient()
  const { data, error } = await supabase
    .from('homeworks')
    .select(`
      id, title, teacher_id, is_published,
      profiles (full_name),
      questions (id, question_text, option_a, option_b, option_c, option_d, order_index)
    `)
    .eq('share_code', shareCode)
    .single()

  if (error || !data || !data.is_published) {
    return null
  }

  // Sort questions by order_index
  const questions = (data.questions as any[]).sort((a,b)=>a.order_index - b.order_index).map((q) => ({
    id: q.id,
    question_text: q.question_text,
    options: [q.option_a, q.option_b, q.option_c, q.option_d],
  }))

  return {
    id: data.id,
    title: data.title,
    teacherName: data.profiles ? (data.profiles as any).full_name : 'Unknown',
    questions: questions,
    totalQuestions: questions.length
  }
}

export type SubmissionInput = {
  shareCode: string;
  studentName: string;
  answers: { questionId: string; selectedIndex: number }[];
}

export async function submitHomework(data: SubmissionInput) {
  const supabase = await createClient()

  // 1. Fetch homework and questions to validate answers
  const { data: hw, error: hwError } = await supabase
    .from('homeworks')
    .select(`id, is_published, questions(id, correct_answer)`)
    .eq('share_code', data.shareCode)
    .single()

  if (hwError || !hw || !hw.is_published) {
    return { error: 'Homework not found or unpublished' }
  }

  const optionMap = ['a', 'b', 'c', 'd']
  let correctCount = 0

  // Check answers
  const answersData = data.answers.map(ans => {
    const question = (hw.questions as any[]).find(q => q.id === ans.questionId)
    const isCorrect = question && question.correct_answer === optionMap[ans.selectedIndex]
    if (isCorrect) correctCount++
    return {
      question_id: ans.questionId,
      selected_option: optionMap[ans.selectedIndex],
      is_correct: isCorrect
    }
  })

  // 2. Insert Submission
  // Note: RLS unique constraint on (homework_id, student_name) might fail here if duplicate
  const { data: subData, error: subError } = await supabase
    .from('submissions')
    .insert({
      homework_id: hw.id,
      student_name: data.studentName,
      score: correctCount,
      total_questions: hw.questions.length
    })
    .select()
    .single()

  if (subError) {
    // Check if it's unique constraint violation
    if (subError.code === '23505') {
       return { error: 'لقد قمت بتسليم هذا الواجب مسبقاً بنفس الاسم.' }
    }
    return { error: subError.message }
  }

  // 3. Insert Answers
  const finalAnswersData = answersData.map(a => ({
    submission_id: subData.id,
    question_id: a.question_id,
    selected_option: a.selected_option,
    is_correct: a.is_correct
  }))

  if (finalAnswersData.length > 0) {
    const { error: ansError } = await supabase.from('answers').insert(finalAnswersData)
    if (ansError) return { error: ansError.message }
  }

  return { success: true, submissionId: subData.id }
}

export async function getSubmissionResult(submissionId: string) {
  const supabase = await createClient()
  const { data, error } = await supabase
    .from('submissions')
    .select(`
      *,
      homeworks (title, teacher_id, profiles(full_name))
    `)
    .eq('id', submissionId)
    .single()

  if (error || !data) return null

  // Fetch ranking
  const { data: rankings, error: rankError } = await supabase
    .from('submissions')
    .select('id, score')
    .eq('homework_id', data.homework_id)
    .order('score', { ascending: false })
    .order('submitted_at', { ascending: true })

  let rank = 0
  if (rankings) {
    rank = rankings.findIndex(r => r.id === submissionId) + 1
  }

  return {
    ...data,
    rank,
    totalStudents: rankings?.length || 1,
    homeworkTitle: (data.homeworks as any).title,
    teacherName: ((data.homeworks as any).profiles as any).full_name,
  }
}

import React from 'react';
import { Card, CardContent } from '../../../components/ui/Card';
import { Button } from '../../../components/ui/Button';
import styles from '../student.module.css';
import { getHomeworkByShareCode } from './actions';
import { notFound } from 'next/navigation';
import { StudentStartForm } from './StudentStartForm';

export default async function StudentStartPage({ params }: { params: Promise<{ id: string }> }) {
  const resolvedParams = await params;
  const shareCode = resolvedParams.id;

  const hw = await getHomeworkByShareCode(shareCode);

  if (!hw) {
    return (
      <div className={styles.cardContainer}>
        <div style={{ textAlign: 'center', padding: '3rem' }}>
           <h2 style={{ color: 'var(--danger)', marginBottom: '1rem' }}>الواجب غير موجود</h2>
           <p>تأكد من الرابط الصحيح من معلمك.</p>
        </div>
      </div>
    );
  }

